    // achievable after deleting any number of elements, causing remaining elements to shift left.

    // Consider an element nums[i] that we decide to keep. 
    // If we keep a subset of the original elements, say at original indices i_1, i_2, ..., i_k,
    // where i_1 < i_2 < ... < i_k, these elements will end up at new indices 0, 1, ..., k-1.
    // The element nums[i_j] will be at new index j-1.
    // For this to be a fixed point, we must have nums[i_j] == j-1.

    // Let's rephrase the condition. We want to select a subsequence of indices $i_1, i_2, \ldots, i_k$ 
    // such that for every j in $\{1, \ldots, k\}$, $nums[i_j] = j-1$.
    // The goal is to maximize k.

    // This is equivalent to finding the longest subsequence of elements $nums[i]$ such that 
    // if the subsequence has length $k$, the $j$-th element ($1$-indexed, so index $j-1$ in the subsequence)
    // has the value $j-1$.

    // We can use a greedy approach or Dynamic Programming, but a greedy approach works here because 
    // the target values (0, 1, 2, ...) are strictly increasing.

    let count = 0; // This will track the required value for the next fixed point (0, 1, 2, ...)

    // Iterate through the original array nums.
    for (let i = 0; i < nums.length; i++) {
        // If nums[i] matches the value required for the next fixed point (which is 'count'),
        // we choose to keep this element to form a fixed point.
        if (nums[i] === count) {
            // We successfully formed a fixed point at the current count index.
            count++;
        }
        // If nums[i] != count, we skip this element (effectively deleting it) because it cannot 
        // contribute to the *next* fixed point at index 'count' (unless we could somehow 
        // make a later element match 'count' when we could have used nums[i]). 
        // Since we are looking for the longest subsequence satisfying the condition, 
        // if nums[i] doesn't match 'count', we must skip it and wait for a larger i 
        // that might match 'count' if we hadn't already passed it, or we just skip it.
        // Since we iterate sequentially, if nums[i] != count, we cannot use it for the current target 'count',
        // so we effectively skip it (delete it) and move on to check nums[i+1] against the same target 'count'.
    }

    // 'count' stores the total number of fixed points found (since it was incremented after the last match).
    return count;
